meta.script:
let recordId=new URLSearchParams(window.location.search).get("recordId")
let number=new URLSearchParams(window.location.search).get("number")
let location=new URLSearchParams(window.location.search).get("location")
const { record, isInit, triggerBy, set = [] } = this;
let triggerRecordFieldChange = "";
if (triggerBy === "shopCode") {
	record.chargeCode = window.recordField.service_application.shopCode.recordValues[record.shopCode];
	return {
	  record,
	  triggerRecordFieldChange
	}
}

if (!recordId){
  return {
    record,
    triggerRecordFieldChange
  }
}
triggerRecordFieldChange = "incidentId";
record.incidentId = recordId;
record.ticketCode = number;
record.shopName = location;
record.no= number;



return {
  record,
  triggerRecordFieldChange
}
